import torch
import pickle
import os
from dataclasses import dataclass

@dataclass
class Vocab:
    word_to_idx: dict
    idx_to_word: list

def verify_model():
    print("Verifying Word2Vec implementation...")

    # Load model
    try:
        model_state = torch.load('/app/model.pt', map_location='cpu')
        print("✓ Model file loaded successfully")

        # Check for embeddings.weight key
        if 'embeddings.weight' in model_state:
            embeddings = model_state['embeddings.weight']
            print(f"✓ Found embeddings.weight in model state")
            print(f"  Embedding shape: {embeddings.shape}")

            # Check embedding dimension
            if embeddings.shape[1] == 300:
                print("✓ Embedding dimension is 300")
            else:
                print(f"✗ Embedding dimension is {embeddings.shape[1]}, expected 300")

            vocab_size = embeddings.shape[0]
            print(f"  Vocabulary size: {vocab_size}")

        else:
            print("✗ embeddings.weight not found in model state")
            print("  Available keys:", list(model_state.keys()))

    except Exception as e:
        print(f"✗ Error loading model: {e}")
        return

    # Load vocabulary
    try:
        with open('/app/vocab.pkl', 'rb') as f:
            vocab = pickle.load(f)
        print("✓ Vocabulary file loaded successfully")

        # Check vocab structure
        if hasattr(vocab, 'word_to_idx') and hasattr(vocab, 'idx_to_word'):
            print("✓ Vocabulary has correct structure (word_to_idx, idx_to_word)")

            # Check vocab size matches model
            if len(vocab.word_to_idx) == vocab_size:
                print("✓ Vocabulary size matches model embedding size")
            else:
                print(f"✗ Vocabulary size mismatch: vocab={len(vocab.word_to_idx)}, model={vocab_size}")

            # Check minimum vocab size
            if len(vocab.word_to_idx) >= 3000:
                print(f"✓ Vocabulary size {len(vocab.word_to_idx)} >= 3000")
            else:
                print(f"✗ Vocabulary size {len(vocab.word_to_idx)} < 3000")

            # Check consistency
            consistent = True
            for word, idx in vocab.word_to_idx.items():
                if idx >= len(vocab.idx_to_word) or vocab.idx_to_word[idx] != word:
                    consistent = False
                    break

            if consistent:
                print("✓ Vocabulary mappings are consistent")
            else:
                print("✗ Vocabulary mappings are inconsistent")

        else:
            print("✗ Vocabulary missing required attributes")

    except Exception as e:
        print(f"✗ Error loading vocabulary: {e}")
        return

    # Check required words
    required_words = {
        "man", "woman", "king", "queen", "girl", "prince", "boy", "father", "mother", 
        "son", "daughter", "brother", "sister", "america", "france", "england", "germany", 
        "japan", "china", "paris", "london", "good", "bad", "big", "small"
    }

    missing_words = required_words - set(vocab.word_to_idx.keys())
    if not missing_words:
        print("✓ All required words present in vocabulary")
    else:
        print(f"✗ Missing required words: {missing_words}")

    # Check file sizes
    model_size = os.path.getsize('/app/model.pt') / (1024 * 1024)  # MB
    vocab_size = os.path.getsize('/app/vocab.pkl') / (1024 * 1024)  # MB

    print(f"\nFile sizes:")
    print(f"  Model: {model_size:.2f} MB")
    print(f"  Vocabulary: {vocab_size:.2f} MB")

    if 5 <= model_size <= 25:
        print("✓ Model size is within required range (5-25 MB)")
    else:
        print(f"✗ Model size {model_size:.2f} MB is outside required range (5-25 MB)")

    print("\nVerification complete!")

if __name__ == "__main__":
    verify_model()
